// Solution
function projectDocument(document, projection) {
  const fields = projection.split(',');
  const result = {};
  for (const field of fields) {
    const [key, subKey] = field.split('.');
    if (subKey && document[key] && typeof document[key] === 'object') {
      result[key] = { ...document[key] }; // deep clone the object
      if (subKey in result[key]) {
        result[key][subKey] = document[key][subKey];
      } else {
        result[key][subKey] = null;
      }
    } else {
      result[key] = document[key];
    }
  }
  return result;
}

