class Solution:
  def projectDocument(self, document, projection):
    fields = projection.split(',');
    result = {};
    for field in fields:
      key, subKey = field.split('.');
      if subKey and document.get(key) and isinstance(document.get(key), dict):
        result[key] = {**document[key]} # deep copy the object
        if subKey in result[key]:
          result[key][subKey] = document[key][subKey]
        else:
          result[key][subKey] = None
      else:
        result[key] = document[key];
    return result;
